  1	import {
  2	  Alert,
  3	  Badge,
  4	  Button,
  5	  MenuToggle,
  6	  MenuToggleElement,
  7	  Select,
  8	  SelectList,
  9	  SelectOption,
 10	  Toolbar,
 11	  ToolbarChip,
 12	  ToolbarChipGroup,
 13	  ToolbarContent,
 14	  ToolbarFilter,
 15	  ToolbarGroup,
 16	} from '@patternfly/react-core';
 17	import React from 'react';
 18	import { useTranslation } from 'react-i18next';
 19	import { useLogsConfig } from '../hooks/LogsConfigProvider';
 20	import { Schema, SchemaConfig } from '../logs.types';
 21	import { Severity, severityFromString } from '../severity';
 22	import { TestIds } from '../test-ids';
 23	import { notUndefined } from '../value-utils';
 24	import { ExecuteQueryButton } from './execute-query-button';
 25	import { ExecuteVolumeButton } from './execute-volume-button';
 26	import { AttributeFilter } from './filters/attribute-filter';
 27	import { AttributeList, Filters } from './filters/filter.types';
 28	import { isOption } from './filters/filters-from-params';
 29	import { LogsQueryInput } from './logs-query-input';
 30	import './logs-toolbar.css';
 31	import { SchemaDropdown } from './schema-dropdown';
 32	import { Spacer } from './spacer';
 33	import { TenantDropdown } from './tenant-dropdown';
 34	import { ToggleButton } from './toggle-button';
 35	import { TogglePlay } from './toggle-play';
 36	
 37	interface LogsToolbarProps {
 38	  query: string;
 39	  onQueryChange?: (query: string) => void;
 40	  onQueryRun?: () => void;
 41	  onVolumeRun?: () => void;
 42	  invalidQueryErrorMessage?: string | null;
 43	  tenant?: string;
 44	  onTenantSelect?: (tenant: string) => void;
 45	  onSchemaSelect?: (schema: Schema) => void;
 46	  enableStreaming?: boolean;
 47	  isStreaming?: boolean;
 48	  severityFilter?: Set<Severity>;
 49	  onStreamingToggle?: (e: React.MouseEvent) => void;
 50	  onSeverityChange?: (severityFilter: Set<Severity>) => void;
 51	  onShowResourcesToggle?: (showResources: boolean) => void;
 52	  onShowStatsToggle?: (showStats: boolean) => void;
 53	  showStats?: boolean;
 54	  showResources?: boolean;
 55	  enableTenantDropdown?: boolean;
 56	  isDisabled?: boolean;
 57	  onFiltersChange?: (filters: Filters) => void;
 58	  filters?: Filters;
 59	  attributeList?: AttributeList;
 60	  onDownloadCSV?: () => void;
 61	  schema: Schema;
 62	}
 63	
 64	const availableSeverityFilters: Array<Severity> = [
 65	  'critical',
 66	  'error',
 67	  'warning',
 68	  'debug',
 69	  'info',
 70	  'trace',
 71	  'unknown',
 72	];
 73	
 74	export const LogsToolbar: React.FC<LogsToolbarProps> = ({
 75	  query,
 76	  onQueryChange,
 77	  onQueryRun,
 78	  onVolumeRun,
 79	  invalidQueryErrorMessage,
 80	  tenant = 'application',
 81	  onTenantSelect,
 82	  onSchemaSelect,
 83	  onStreamingToggle,
 84	  onShowResourcesToggle,
 85	  onDownloadCSV,
 86	  showResources = false,
 87	  onShowStatsToggle,
 88	  showStats = false,
 89	  enableStreaming = false,
 90	  isStreaming = false,
 91	  enableTenantDropdown = true,
 92	  isDisabled = false,
 93	  filters,
 94	  onFiltersChange,
 95	  attributeList,
 96	  schema,
 97	}) => {
 98	  const { t } = useTranslation('plugin__logging-view-plugin');
 99	
100	  const [isSeverityExpanded, setIsSeverityExpanded] = React.useState(false);
101	  const [isQueryShown, setIsQueryShown] = React.useState(false);
102	  const [isSchemaShown, setIsSchemaShown] = React.useState(false);
103	
104	  const { config } = useLogsConfig();
105	
106	  const severitySelectRef = React.useRef<HTMLDivElement>(null);
107	
108	  const handleClickOutside = (event: MouseEvent) => {
109	    if (isSeverityExpanded && !severitySelectRef.current?.contains(event.target as Node)) {
110	      setIsSeverityExpanded(false);
111	    }
112	  };
113	
114	  React.useEffect(() => {
115	    if (isSeverityExpanded) {
116	      window.addEventListener('click', handleClickOutside);
117	    }
118	    return () => {
119	      window.removeEventListener('click', handleClickOutside);
120	    };
121	  }, [isSeverityExpanded]);
122	
123	  React.useEffect(() => {
124	    if (config?.schema === SchemaConfig.select) {
125	      setIsSchemaShown(true);
126	    }
127	  }, [config?.schema]);
128	
129	  const severityFilter: Set<Severity> = filters?.severity
130	    ? new Set(Array.from(filters?.severity).map(severityFromString).filter(notUndefined))
131	    : new Set();
132	
133	  const onDeleteSeverityFilter = (
134	    _category: string | ToolbarChipGroup,
135	    chip: string | ToolbarChip,
136	  ) => {
137	    severityFilter.delete(chip.toString() as Severity);
138	    const newFilters = { ...(filters ?? {}), severity: severityFilter };
139	    onFiltersChange?.(newFilters);
140	  };
141	
142	  const handleClearAllFilters = () => {
143	    onFiltersChange?.({});
144	  };
145	
146	  const onDeleteSeverityGroup = () => {
147	    onFiltersChange?.({ ...(filters ?? {}), severity: undefined });
148	  };
149	
150	  const onSeverityToggle = () => {
151	    setIsSeverityExpanded(!isSeverityExpanded);
152	  };
153	
154	  const onSeveritySelect = (
155	    _: React.MouseEvent<Element, MouseEvent> | undefined,
156	    value: string | number | undefined,
157	  ) => {
158	    const severityValue = (isOption(value) ? value.value : String(value)) as Severity;
159	
160	    if (severityFilter.has(severityValue)) {
161	      severityFilter.delete(severityValue);
162	    } else {
163	      severityFilter.add(severityValue);
164	    }
165	
166	    onFiltersChange?.({
167	      ...(filters ?? {}),
168	      severity: new Set(severityFilter),
169	    });
170	  };
171	
172	  const severityFilterArray = Array.from(severityFilter);
173	
174	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
175	    <MenuToggle
176	      isDisabled={isDisabled}
177	      ref={toggleRef}
178	      onClick={onSeverityToggle}
179	      isExpanded={isSeverityExpanded}
180	      style={
181	        {
182	          width: '200px',
183	        } as React.CSSProperties
184	      }
185	    >
186	      {t('Severity')}
187	      {severityFilterArray.length > 0 && <Badge isRead>{severityFilterArray.length}</Badge>}
188	    </MenuToggle>
189	  );
190	
191	  return (
192	    <Toolbar isSticky clearAllFilters={handleClearAllFilters} className="lv-plugin__toolbar">
193	      <ToolbarContent>
194	        {attributeList && (
195	          <AttributeFilter
196	            attributeList={attributeList}
197	            filters={filters}
198	            onFiltersChange={onFiltersChange}
199	            tenant={tenant}
200	          />
201	        )}
202	
203	        <ToolbarGroup>
204	          <ToolbarFilter
205	            labels={severityFilterArray}
206	            deleteLabel={onDeleteSeverityFilter}
207	            deleteLabelGroup={onDeleteSeverityGroup}
208	            categoryName="Severity"
209	            className="lv-plugin__severity-filter"
210	            data-test={TestIds.SeverityDropdown}
211	          >
212	            <div ref={severitySelectRef}>
213	              <Select
214	                aria-label="Severity"
215	                toggle={toggle}
216	                onSelect={onSeveritySelect}
217	                placeholder={t('Severity')}
218	                isOpen={isSeverityExpanded}
219	              >
220	                <SelectList>
221	                  {availableSeverityFilters.map((severity) => (
222	                    <SelectOption
223	                      key={severity}
224	                      value={severity}
225	                      isSelected={severityFilterArray.some(
226	                        (selectedSeverity) => selectedSeverity === severity,
227	                      )}
228	                      hasCheckbox={true}
229	                    >
230	                      {severity}
231	                    </SelectOption>
232	                  ))}
233	                </SelectList>
234	              </Select>
235	            </div>
236	          </ToolbarFilter>
237	        </ToolbarGroup>
238	
239	        {enableTenantDropdown && (
240	          <ToolbarGroup>
241	            <TenantDropdown onTenantSelected={onTenantSelect} selectedTenant={tenant} />
242	          </ToolbarGroup>
243	        )}
244	
245	        {isSchemaShown && (
246	          <ToolbarGroup>
247	            <SchemaDropdown onSchemaSelected={onSchemaSelect} schema={schema} />
248	          </ToolbarGroup>
249	        )}
250	
251	        <ToolbarGroup>
252	          <ToggleButton
253	            isToggled={showResources}
254	            onToggle={onShowResourcesToggle}
255	            untoggledText={t('Show Resources')}
256	            toggledText={t('Hide Resources')}
257	          />
258	
259	          <ToggleButton
260	            isToggled={showStats}
261	            onToggle={onShowStatsToggle}
262	            untoggledText={t('Show Stats')}
263	            toggledText={t('Hide Stats')}
264	            data-test={TestIds.ShowStatsToggle}
265	          />
266	        </ToolbarGroup>
267	
268	        <ToolbarGroup>
269	          {onDownloadCSV && (
270	            <ToolbarGroup>
271	              <Button variant="secondary" isInline onClick={onDownloadCSV}>
272	                {t('Export as CSV')}
273	              </Button>
274	            </ToolbarGroup>
275	          )}
276	
277	          <ToolbarGroup>
278	            <ExecuteVolumeButton onClick={onVolumeRun} isDisabled={isDisabled} />
279	          </ToolbarGroup>
280	
281	          {!isQueryShown && (
282	            <>
283	              <ToolbarGroup>
284	                <ExecuteQueryButton onClick={onQueryRun} isDisabled={isDisabled} />
285	              </ToolbarGroup>
286	              {invalidQueryErrorMessage && (
287	                <ToolbarGroup>
288	                  <Alert variant="danger" isInline isPlain title={invalidQueryErrorMessage} />
289	                </ToolbarGroup>
290	              )}
291	            </>
292	          )}
293	
294	          <Spacer />
295	
296	          <ToolbarGroup>
297	            <ToggleButton
298	              isToggled={isQueryShown}
299	              onToggle={setIsQueryShown}
300	              untoggledText={t('Show Query')}
301	              toggledText={t('Hide Query')}
302	              data-test={TestIds.ShowQueryToggle}
303	            />
304	          </ToolbarGroup>
305	        </ToolbarGroup>
306	
307	        {enableStreaming && (
308	          <ToolbarGroup>
309	            <TogglePlay isDisabled={isDisabled} active={isStreaming} onClick={onStreamingToggle} />
310	          </ToolbarGroup>
311	        )}
312	      </ToolbarContent>
313	
314	      {isQueryShown && (
315	        <LogsQueryInput
316	          value={query}
317	          onRun={onQueryRun}
318	          onChange={onQueryChange}
319	          invalidQueryErrorMessage={invalidQueryErrorMessage}
320	          isDisabled={isDisabled}
321	          tenant={tenant}
322	        />
323	      )}
324	    </Toolbar>
325	  );
326	};

